import{_ as a,c as s,o as n,a4 as l}from"./chunks/framework.I1cCAST3.js";const p="/assets/skill2.OkENhr0n.webp",e="/assets/skill3.DxUq-dVb.webp",t="/assets/skill4.CkgfOAO_.webp",i="/assets/skill5.CfiyDcLU.webp",r="/assets/skill6.B-n-mjkO.webp",o="/assets/skill7.CBTgnhb8.webp",c="/assets/skill8.BsS5uuLn.webp",h="/assets/skill9.XyI5en6S.webp",k="/assets/skill10.BjZcPf8t.webp",m="/assets/skill11.Cccq3RE0.webp",I=JSON.parse('{"title":"Agent Skills + 千问大模型，智能运维再进化","description":"","frontmatter":{"title":"Agent Skills + 千问大模型，智能运维再进化","author":"Aliyun Blogs","date":"2026-2-25","top":true,"sticky":15,"comment":false,"category":"Technical","tags":["Agent","Skills","Confluence","Aliyun","AIOPS"],"blog":"post","aside":"left","sidebar":false,"prev":false,"next":false},"headers":[],"relativePath":"blog/posts/skills.md","filePath":"blog/posts/skills.md"}'),d={name:"blog/posts/skills.md"},u=l('<p>通过深度集成千问大模型，Chaterm 的 Agent Skills 可以将运维经验&quot;打包&quot;成可执行技能，让AI助手自动执行标准流程。</p><p>依托Qwen模型强大的语义理解、可靠的命令生成和智能的Agent任务规划能力，Chaterm为使用者提供更加智能和新颖的运维体验，将日常需要20分钟的任务缩短到3分钟，并在故障发生时基于以往经验快速排查和恢复。本文从 Skills 的概念、工作原理、技术实现，到实战案例，让其成为你专属的&quot;AI运维专家&quot;。</p><hr><h2 id="一个真实的凌晨3点" tabindex="-1">一个真实的凌晨3点 <a class="header-anchor" href="#一个真实的凌晨3点" aria-label="Permalink to &quot;一个真实的凌晨3点&quot;">​</a></h2><p>上周三的凌晨3点，我被云监控系统的告警信息叫醒。</p><p>“【Confluence系统】 <a href="http://192.168.0.1:8090/pages/#all-updates" target="_blank" rel="noreferrer">http://192.168.0.1:8090/pages/#all-updates</a> 无法访问！”</p><p>我迷迷糊糊打开电脑，通过Chaterm连上云服务器，开始敲命令：netstat -nplut、top、systemctl status confluence、tail -f… 看着满屏的输出，我一边揉眼睛一边分析，花了 20 分钟才找到问题：凌晨系统负载过高导致异常停止，其中又因自动备份的 gzip 进程一直占用资源，导致系统服务一直重启失败。</p><p>【内心OS】如果当时我有个 Skill，可能 3 分钟就搞定了。</p><p><img src="'+p+'" alt=""></p><p>这就是今天要聊的 Skills。它不是另一个 AI 概念，而是一个真正能帮你把运维经验&quot;打包&quot;成可执行技能的工具。今天我们就从 Skills 是什么、怎么工作，一路聊到怎么写好一个 Skill，最后在 Chaterm 里实际落地一个基于阿里云的运维场景。</p><h2 id="chaterm-skills简介" tabindex="-1">Chaterm Skills简介 <a class="header-anchor" href="#chaterm-skills简介" aria-label="Permalink to &quot;Chaterm Skills简介&quot;">​</a></h2><h3 id="什么是chaterm" tabindex="-1">什么是Chaterm <a class="header-anchor" href="#什么是chaterm" aria-label="Permalink to &quot;什么是Chaterm&quot;">​</a></h3><p>Chaterm 是一款开源AI智能终端和SSH客户端。旨在通过自然语言交互重构传统的命令行操作体验。它的目标是成为您的DevOps智能副驾驶。目前已支持 Mac/Windows/Linux/iOS/安卓等多个环境。Chaterm旨在解决大规模云环境下运维工作中批量化操作、故障排查复杂和安全管控困难等痛点。它将 AI Agent能力直接嵌入终端，通过打造“对话式终端管理工具”，帮助服务端开发者、DEVOPS工程师、云计算从业人士实现云资源的智能化和规模化管理。</p><p><img src="'+e+`" alt=""></p><h3 id="什么是skills" tabindex="-1">什么是Skills <a class="header-anchor" href="#什么是skills" aria-label="Permalink to &quot;什么是Skills&quot;">​</a></h3><p><strong>Skills</strong> 这个概念最早由 Anthropic 公司提出，简单来说，它让用户可以把专业知识、操作步骤、最佳实践封装成 Skills，让 AI 自动识别并执行。</p><p>随着这套做法越来越成熟，并被社区广泛接受，Skills 如今已成为大多数 AI Coding 和 AI。</p><p>工具都支持的一种标准扩展规范。从Claude Code、Qoder、Cursor到 Chaterm，很多AI工具都基于这个规范实现了自己的Skills 系统。</p><p>Chaterm 也不例外。它基于这个规范，让运维工程师可以把在阿里云上日常的检查清单、应用/数据库部署流程、故障排查流程、性能优化步骤等，都封装成 Skills。这样，AI 助手就不再是<strong>通用助手</strong>，而是真正懂你业务的<strong>专家助手</strong>。</p><h3 id="skills的标准结构" tabindex="-1">Skills的标准结构 <a class="header-anchor" href="#skills的标准结构" aria-label="Permalink to &quot;Skills的标准结构&quot;">​</a></h3><p>一个 Skill 通常以一个文件夹的形式存在，里面主要包含三样东西：</p><p>一份说明书（SKILL.md）、操作脚本（Script）、以及参考资料（Reference）。</p><table tabindex="0"><thead><tr><th>内容</th><th>作用</th></tr></thead><tbody><tr><td>SKILL.md</td><td>通过自然语言清晰描述（使用场景、使用方式、使用步骤及注意事项等上下文补充信息）</td></tr><tr><td>Script 脚本</td><td>Agent 可以执行的具体脚本代码</td></tr><tr><td>Reference 引用</td><td>参考文档、引用的模板、相关关联上下文的文件信息</td></tr></tbody></table><p>你可以把一个 Skill 想象成一个打包好的&quot;技能包&quot;。它把完成某个特定任务所需的领域知识、操作流程、要用到的工具以及最佳实践全都封装在了一起。当 AI 面对相应请求时，就能像一位经验丰富的专家那样，有条不紊地自主执行。</p><p>一句话总结：如果把 Agent 比作一个有很大潜力的大脑，那 Skills 就像是给这个大脑的一套套能反复使用的&quot;技能手册&quot;。有了它，Agent 能从一个&quot;什么都略知一二&quot;的通才，变成在特定领域&quot;得心应手&quot;的专家。</p><p>每个 SKILL.md 文件遵循以下格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: skill-name</span></span>
<span class="line"><span>description: Skill description</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Skill Title</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Workflow Step</span></span>
<span class="line"><span>[详细的工作流程和命令]</span></span></code></pre></div><p>就这么简单。AI 看到这个 Skill，就知道怎么做了。</p><h3 id="chaterm-skills是怎么工作的" tabindex="-1">Chaterm Skills是怎么工作的？ <a class="header-anchor" href="#chaterm-skills是怎么工作的" aria-label="Permalink to &quot;Chaterm Skills是怎么工作的？&quot;">​</a></h3><p><img src="`+t+'" alt=""></p><p>在 Chaterm 里，Skills 的工作流程是这样的：</p><p><strong>1. 加载阶段：</strong> Chaterm 启动时，会扫描 Skills 目录，读取所有 SKILL.md 文件；</p><p><strong>2. 注入阶段：</strong> 启用的 Skills 会被注入到 AI 的系统提示中，告诉 AI 有哪些技能可用；</p><p><strong>3. 识别阶段：</strong> 当你提出需求时，AI 会分析你的请求，判断是否需要使用某个 Skill；</p><p><strong>4. 执行阶段：</strong> 如果匹配，AI 会调用 use_skill 工具，获取完整的 Skill 内容，然后按照流程执行；</p><p>整个过程对用户是透明的。你只需要说<strong>检查一下阿里云ECS上的 Confluence 系统状态</strong>，AI 会自动识别并使用 Confluence-health-check Skill。</p><h3 id="为什么chaterm-skills适合运维场景" tabindex="-1">为什么Chaterm Skills适合运维场景 <a class="header-anchor" href="#为什么chaterm-skills适合运维场景" aria-label="Permalink to &quot;为什么Chaterm Skills适合运维场景&quot;">​</a></h3><p><img src="'+i+`" alt=""></p><p>运维工作有几个特点，让 Skills 特别有价值：</p><h3 id="_1-标准化程度高" tabindex="-1">1. 标准化程度高 <a class="header-anchor" href="#_1-标准化程度高" aria-label="Permalink to &quot;1. 标准化程度高&quot;">​</a></h3><p>系统健康检查、应用中间件/数据库等服务部署、日志分析、故障排查，这些都有相对标准的流程。一个资深运维的操作手册，往往能覆盖 80% 的场景。</p><h3 id="_2-重复性操作多" tabindex="-1">2. 重复性操作多 <a class="header-anchor" href="#_2-重复性操作多" aria-label="Permalink to &quot;2. 重复性操作多&quot;">​</a></h3><p>你每天可能都要检查系统状态、部署服务、分析日志、排查问题。每次都重新描述一遍流程，太累了。Skills 让你&quot;一次写好，永久使用&quot;。</p><h3 id="_3-经验难以传承" tabindex="-1">3. 经验难以传承 <a class="header-anchor" href="#_3-经验难以传承" aria-label="Permalink to &quot;3. 经验难以传承&quot;">​</a></h3><p>团队里老王的排查经验，新来的小李怎么快速学会？写文档？看代码？都不如直接给他一个 Skills，让他跟着 AI 做一遍。</p><h3 id="_4-错误成本高" tabindex="-1">4. 错误成本高 <a class="header-anchor" href="#_4-错误成本高" aria-label="Permalink to &quot;4. 错误成本高&quot;">​</a></h3><p>生产环境操作错了，可能造成严重后果。Skills 把最佳实践固化下来，减少人为错误。</p><h2 id="用chaterm-skills落地一个阿里云上的运维场景" tabindex="-1">用Chaterm Skills落地一个阿里云上的运维场景 <a class="header-anchor" href="#用chaterm-skills落地一个阿里云上的运维场景" aria-label="Permalink to &quot;用Chaterm Skills落地一个阿里云上的运维场景&quot;">​</a></h2><p>理论说再多，不如实操一遍。下面我从Skill创建到使用，和大家一起走一遍完整流程。</p><h3 id="场景-创建一个-confluence-系统异常检查-skill" tabindex="-1">场景：创建一个&quot;Confluence 系统异常检查&quot; Skill <a class="header-anchor" href="#场景-创建一个-confluence-系统异常检查-skill" aria-label="Permalink to &quot;场景：创建一个&quot;Confluence 系统异常检查&quot; Skill&quot;">​</a></h3><p>假设你在阿里云ECS上部署了 Confluence ，经常遇到系统异常的问题，想创建一个专门的 Skill 来检查和处理。</p><h3 id="步骤-1-规划-skill" tabindex="-1">步骤 1：规划 Skill <a class="header-anchor" href="#步骤-1-规划-skill" aria-label="Permalink to &quot;步骤 1：规划 Skill&quot;">​</a></h3><p>首先想清楚：</p><p><strong>名称：</strong> confluence-health-check；</p><p><strong>描述：</strong> 检查 Confluence 系统状态，包括服务状态、服务端口、CPU、内存、磁盘、日志；</p><h3 id="步骤-2-设计skill-md的工作流程" tabindex="-1">步骤 2：设计SKILL.md的工作流程 <a class="header-anchor" href="#步骤-2-设计skill-md的工作流程" aria-label="Permalink to &quot;步骤 2：设计SKILL.md的工作流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: confluence-health-check</span></span>
<span class="line"><span>description: 检查 Confluence 系统状态，包括服务状态、服务端口、CPU、内存、磁盘、日志</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Confluence 系统检查</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 工作流程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 第一步：检查服务状态和端口</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 切换到root权限</span></span>
<span class="line"><span>sudo su -</span></span>
<span class="line"><span># 服务状态</span></span>
<span class="line"><span>systemctl status confluence</span></span>
<span class="line"><span>netstat -nplut | grep 8090</span></span>
<span class="line"><span>netstat -nplut | grep 8091</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 第二步：检查系统资源</span></span>
<span class="line"><span></span></span>
<span class="line"><span># CPU 和内存</span></span>
<span class="line"><span>top -bn1 | head -20</span></span>
<span class="line"><span>free -h</span></span>
<span class="line"><span>uptime</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 内存使用情况</span></span>
<span class="line"><span>free -h</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 磁盘使用情况</span></span>
<span class="line"><span>df -h</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 第三步：检查进程和日志</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 进程状态</span></span>
<span class="line"><span>ps aux | grep confluence | grep -v grep</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 第五步：检查系统日志</span></span>
<span class="line"><span>查看系统日志和 Confluence 日志中的错误信息：</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 系统日志中的 Confluence 相关错误</span></span>
<span class="line"><span>journalctl -u confluence -p err --no-pager | tail -20</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Confluence 应用日志</span></span>
<span class="line"><span>tail -50 /var/atlassian/application-data/confluence/log/atlassian-confluence.log 2&gt;/dev/null</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 检查最近的错误</span></span>
<span class="line"><span>grep -i &quot;error\\|exception\\|fail&quot; /var/atlassian/application-data/confluence/log/*.log 2&gt;/dev/null | tail -30</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 收集数据后，按以下标准进行分析：</span></span>
<span class="line"><span>### 1. 服务状态</span></span>
<span class="line"><span>- 正常状态：\`systemctl status\` 显示 \`active (running)\`</span></span>
<span class="line"><span>- 异常状态：如果显示 \`inactive\`、\`failed\` 或 \`dead\`，需要立即处理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 2. 端口状态</span></span>
<span class="line"><span>- 8090 端口：必须处于 \`LISTEN\` 状态</span></span>
<span class="line"><span>- 8091 端口：如果启用了 HTTPS，必须处于 \`LISTEN\` 状态</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 3. CPU 使用情况</span></span>
<span class="line"><span>- 负载平均值：应该小于 CPU 核心数</span></span>
<span class="line"><span>- CPU 使用率：正常运行时应该在 50% 以下</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 4. 内存使用情况</span></span>
<span class="line"><span>- 可用内存：应该大于总内存的 10%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 5. 磁盘使用情况</span></span>
<span class="line"><span>- 系统盘（/）：可用空间应该大于 10%</span></span>
<span class="line"><span>- 数据目录（/data）：可用空间应该大于 10%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 6. 进程状态</span></span>
<span class="line"><span>- 进程数量：通常应该有多个 Java 进程（主进程 + 工作进程）</span></span>
<span class="line"><span>- 进程资源占用：如果单个进程占用过高，可能存在内存泄漏或性能问题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 7. 日志分析</span></span>
<span class="line"><span>- 错误日志：检查是否有重复的错误模式</span></span>
<span class="line"><span>- 异常信息：关注 \`OutOfMemoryError\`、\`ConnectionException\` 等关键异常</span></span></code></pre></div><h3 id="步骤-3-在-chaterm-中创建-skill" tabindex="-1">步骤 3：在 Chaterm 中创建 Skill <a class="header-anchor" href="#步骤-3-在-chaterm-中创建-skill" aria-label="Permalink to &quot;步骤 3：在 Chaterm 中创建 Skill&quot;">​</a></h3><p><strong>方法 A：通过 UI 创建</strong></p><ol><li><p>打开 Chaterm</p></li><li><p>点击左侧设置图标 → 选择 “Skills”</p></li><li><p>点击右上角 “创建技能” 按钮</p></li><li><p>填写表单：</p></li></ol><p><strong>名称：</strong> confluence-health-check</p><p><strong>描述：</strong> 检查 Confluence 系统状态，包括服务状态、服务端口、CPU、内存、磁盘</p><p><strong>内容：</strong> 复制上面完整的 Skill 内容（从 --- 开始）</p><ol start="5"><li>点击 “创建”</li></ol><p><strong>方法 B：直接创建文件</strong></p><ol><li><p>在 Skills 页面点击 “打开文件夹” 按钮</p></li><li><p>创建新文件夹 confluence-health-check</p></li><li><p>在该文件夹中创建 SKILL.md 文件</p></li><li><p>将 Skill 内容复制到文件中</p></li><li><p>返回 Chaterm，点击 “重新加载” 按钮</p></li></ol><h3 id="步骤-4-使用-skill" tabindex="-1">步骤 4：使用 Skill <a class="header-anchor" href="#步骤-4-使用-skill" aria-label="Permalink to &quot;步骤 4：使用 Skill&quot;">​</a></h3><p>创建完成后，在 Chaterm 的对话窗口中，你可以直接描述需求：</p><p><code>检查一下阿里云ECS上的 Confluence 系统状态</code></p><p>AI 会自动识别并使用 confluence-health-check Skill，按照工作流程执行操作。</p><p><img src="`+r+`" alt=""></p><h3 id="步骤-5-优化和迭代" tabindex="-1">步骤 5：优化和迭代 <a class="header-anchor" href="#步骤-5-优化和迭代" aria-label="Permalink to &quot;步骤 5：优化和迭代&quot;">​</a></h3><p>使用几次后，你可能会发现：</p><ul><li><p>某些命令执行太慢，需要优化</p></li><li><p>缺少某些执行命令项，需要补充</p></li><li><p>执行的步骤不完整，需要调整</p></li></ul><p>这时候你可以：</p><ol><li><p>编辑 Skill 文件（在 Skills 目录中直接修改文件）</p></li><li><p>重新加载 Skills</p></li><li><p>再次测试</p></li></ol><p>这就是 Skills 的优势：可以持续优化，越用越好。</p><h2 id="chaterm-skills的技术实现" tabindex="-1">Chaterm Skills的技术实现 <a class="header-anchor" href="#chaterm-skills的技术实现" aria-label="Permalink to &quot;Chaterm Skills的技术实现&quot;">​</a></h2><p>这里我们来看下Chaterm的技术实现。</p><p><strong>Chaterm Skills：</strong></p><p>Skills 的存储结构</p><p>在 Chaterm 中，Skills 存储在用户数据目录下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Chaterm/skills/</span></span>
<span class="line"><span>├── confluence-health-check/</span></span>
<span class="line"><span>│   └── SKILL.md</span></span>
<span class="line"><span>├── log-analyzer/</span></span>
<span class="line"><span>│   └── SKILL.md</span></span>
<span class="line"><span>└── mysql-deploy/</span></span>
<span class="line"><span>    ├── SKILL.md</span></span>
<span class="line"><span>    ├── scripts/</span></span>
<span class="line"><span>    │   └── db_init.py</span></span>
<span class="line"><span>    └── references/</span></span>
<span class="line"><span>        └── workflow.md</span></span></code></pre></div><p>每个 Skill 是一个文件夹，里面必须有一个 SKILL.md 文件。还可以放一些资源文件，比如脚本、模板等。</p><p><strong>Skills 的加载机制</strong></p><p>Chaterm 启动时会：</p><ol><li>解析每个 SKILL.md 文件：</li></ol><ul><li><p>提取 frontmatter（名称、描述）</p></li><li><p>读取完整内容</p></li><li><p>扫描资源文件</p></li></ul><ol start="2"><li>注册到系统：</li></ol><ul><li><p>存储到内存的 Map 中</p></li><li><p>从数据库加载启用状态</p></li><li><p>注入到 AI 的系统提示</p></li></ul><p><strong>Skills 的触发机制</strong></p><p>当 AI 收到你的请求时：</p><p><strong>1. 分析任务：</strong> 理解你要做什么</p><p><strong>2. 匹配 Skills：</strong> 看看可用的 Skills 中，哪个的描述和你的需求匹配</p><p><strong>3. 调用工具：</strong> 如果匹配，调用 use_skill 工具，传入 Skill 名称</p><p><strong>4. 获取内容：</strong> 系统返回完整的 Skill 内容（包括工作流程、分析指南等）</p><p><strong>5. 执行流程：</strong> AI 按照 Skill 中的步骤，调用其他工具（如 execute_command）完成任务</p><p>整个过程是自动的，你不需要手动指定使用哪个 Skill。</p><h3 id="chaterm集成qwen大模型" tabindex="-1">Chaterm集成Qwen大模型： <a class="header-anchor" href="#chaterm集成qwen大模型" aria-label="Permalink to &quot;Chaterm集成Qwen大模型：&quot;">​</a></h3><p>千问大模型是阿里巴巴集团自主研发的超大规模语言模型，具备强大的语言理解、多语言支持、代码生成与逻辑推理能力。其作为最大的全球开源模型家族，被全球数十万开发者广泛采用。Qwen 多次入选Gartner、IDC、Forrester及Omdia等多家国际权威评测榜单前列，综合性能达到国际先进水平。</p><p>当前千问大模型与Chaterm 强强联合，在Chaterm的Chat、Command、Agent三种模式下均将千问大模型的Qwen-Plus与Qwen-Turbo作为推荐模型进行集成。提供的AI Agent能力直接嵌入终端并结合千问大模型强大的能力打造“对话式终端管理工具”，帮助服务端开发者、DEVOPS工程师、云计算从业人士实现云资源的智能化和规模化管理，开启云上运维新范式。</p><p><img src="`+o+'" alt=""></p><p>千问近期还推出了最新的旗舰推理模型Qwen3-Max-Thinking，在事实知识、复杂推理、指令遵循、人类偏好对齐以及智能体能力得到了显著提升。在19项权威基准测试中，其性能可媲美 GPT-5.2-Thinking、Claude-Opus-4.5 和 Gemini 3 Pro 等顶尖模型。Qwen3-Max-Thinking现已上线阿里云百炼平台和Qwen Chat，可供大家快速体验。</p><h2 id="通过chaterm实现阿里云堡垒机资产一键直连" tabindex="-1">通过Chaterm实现阿里云堡垒机资产一键直连 <a class="header-anchor" href="#通过chaterm实现阿里云堡垒机资产一键直连" aria-label="Permalink to &quot;通过Chaterm实现阿里云堡垒机资产一键直连&quot;">​</a></h2><p><img src="'+c+'" alt=""></p><p>除了Agent Skills， Chaterm还能让你告别传统方式，实现真正的&quot;一键直连&quot;。</p><p>传统方式需要：</p><ul><li>打开阿里云控制台 → 找到资产 → 复制IP → 配置SSH → 输入密码 → 连接...</li></ul><p>现在，<strong>Chaterm 支持一键直连</strong>。</p><p><img src="'+h+'" alt=""></p><p><strong>功能特性：</strong></p><p>刷新同步资产列表，管理更高效</p><p>点击资产即可直连，无需手动配置</p><p>安全凭证自动管理，告别重复输入</p><p><strong>配置方式：</strong></p><ol><li><p>在 Chaterm 中配置阿里云堡垒机认证信息</p></li><li><p>刷新同步堡垒机资产列表</p></li><li><p>点击资产，快速连接</p></li></ol><p><strong>Chaterm 让阿里云堡垒机资产管理更简单高效。</strong></p><p><img src="'+k+'" alt=""></p><h2 id="如何用好chaterm-skills" tabindex="-1">如何用好Chaterm Skills <a class="header-anchor" href="#如何用好chaterm-skills" aria-label="Permalink to &quot;如何用好Chaterm Skills&quot;">​</a></h2><p>写 Skills 不是从零开始，有很多现成的资源可以参考。</p><h3 id="skills-标准规范" tabindex="-1">Skills 标准规范 <a class="header-anchor" href="#skills-标准规范" aria-label="Permalink to &quot;Skills 标准规范&quot;">​</a></h3><p>Skills 遵循一个开放的标准规范。了解规范有助于写出兼容性更好的 Skills。</p><p><strong>核心要求：</strong></p><p>必须包含 frontmatter（name 和 description）</p><p>支持资源文件（脚本、引用参考文档等）</p><h3 id="skills社区资源" tabindex="-1">Skills社区资源 <a class="header-anchor" href="#skills社区资源" aria-label="Permalink to &quot;Skills社区资源&quot;">​</a></h3><p>Anthropic 提供的 Skills 示例：<a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">https://github.com/anthropics/skills</a></p><p>Chaterm 提供了运维场景的 Skills 示例：<a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">https://github.com/chaterm/terminal-skills</a></p><p>Github还有很多仓库提供了 Skills 示例，这里就不一一列举了。</p><p>这些示例你可以：</p><ol><li><p>直接复制到 Chaterm 中使用</p></li><li><p>基于它们修改成自己的版本</p></li><li><p>学习它们的结构和写法</p></li></ol><h3 id="总结-chaterm-agent-skills-改变了什么" tabindex="-1">总结：Chaterm Agent Skills 改变了什么？ <a class="header-anchor" href="#总结-chaterm-agent-skills-改变了什么" aria-label="Permalink to &quot;总结：Chaterm Agent Skills 改变了什么？&quot;">​</a></h3><p><img src="'+m+'" alt=""></p><p>回到开头那个凌晨 3 点的场景。</p><p><strong>以前：</strong></p><ul><li><p>手动执行命令</p></li><li><p>从一堆输出中找问题</p></li><li><p>依赖个人经验</p></li><li><p>容易遗漏关键检查项</p></li><li><p>每次都要重新来一遍</p></li></ul><p><strong>现在：</strong></p><ul><li><p>AI自动执行标准流程</p></li><li><p>生成结构化的诊断报告</p></li><li><p>遵循团队最佳实践</p></li><li><p>检查项完整，不会遗漏</p></li><li><p>一次写好，永久使用</p></li></ul><p>Skills 不是要替代运维工程师，而是让 AI 助手真正成为你的&quot;专家助手&quot;。它把你的经验固化下来，让团队共享，让新人快速上手。</p><p>最重要的是，Skills 是开放的、可定制的。你可以根据自己的需求，创建属于自己的 Skills。从解决实际问题开始，逐步建立你的 Skills 库。</p><h3 id="下一步行动" tabindex="-1">下一步行动 <a class="header-anchor" href="#下一步行动" aria-label="Permalink to &quot;下一步行动&quot;">​</a></h3><ol><li><p><strong>体验 Chaterm：</strong> 如果还没用过，去 <a href="https://chaterm.cn/download/" target="_blank" rel="noreferrer">https://chaterm.cn/download/</a> 下载体验</p></li><li><p><strong>查看示例：</strong> 在 GitHub 上查看官方的 Skills 示例</p></li><li><p><strong>创建第一个 Skill：</strong> 从你最常用的操作开始，写一个简单的 Skill</p></li><li><p><strong>分享交流：</strong> 在社区分享你的 Skills，或者从别人那里学习</p></li></ol><p>Skills 的价值在于使用，请开始写你的第一个 Skill 吧！！！</p><h3 id="相关网站" tabindex="-1">相关网站： <a class="header-anchor" href="#相关网站" aria-label="Permalink to &quot;相关网站：&quot;">​</a></h3><p>Chaterm 官网：<a href="https://chaterm.ai" target="_blank" rel="noreferrer">https://chaterm.ai</a></p><p>阿里云百炼官网：<a href="https://www.aliyun.com/product/bailian" target="_blank" rel="noreferrer">https://www.aliyun.com/product/bailian</a></p><p>Qwen Chat：<a href="https://chat.qwen.ai" target="_blank" rel="noreferrer">https://chat.qwen.ai</a></p><p>GitHub 仓库：<a href="https://github.com/chaterm/Chaterm" target="_blank" rel="noreferrer">https://github.com/chaterm/Chaterm</a></p><p>Skills 示例：<a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">https://github.com/chaterm/terminal-skills</a></p>',149),g=[u];function S(b,f,C,q,_,A){return n(),s("div",null,g)}const x=a(d,[["render",S]]);export{I as __pageData,x as default};
